from __future__ import annotations

import codecs
import json
import os
import selectors
import subprocess
import time
from dataclasses import dataclass
from pathlib import Path
from typing import Any, Mapping, Sequence

from ._connect import post_bridge_shutdown
from ._local_store import LocalAgentStoreHandler
from ._store_callback import (
    StoreCallbackServer,
    local_store_bridge_argv,
    resolve_store_callback_handler_for_launch,
    store_callback_bridge_argv,
)
from ._tool_callback import ToolCallbackServer, tool_callback_bridge_argv
from ._vendor import resolve_bridge_path
from .errors import CursorSDKError
from .types import CustomTool, LocalAgentOptions

READY_LINE_PREFIX = "cursor-sdk-bridge ready "

# Lets the backend identify Python SDK callers (sdk_python_preview_access
# Statsig flag). setdefault so a caller-set value wins.
_BRIDGE_LANGUAGE_ENV = "CURSOR_SDK_CLIENT_LANGUAGE"
_BRIDGE_PYTHON_VERSION_ENV = "CURSOR_SDK_PYTHON_VERSION"


def _bridge_subprocess_env() -> Mapping[str, str]:
    env = dict(os.environ)
    env.setdefault(_BRIDGE_LANGUAGE_ENV, "python")
    if _BRIDGE_PYTHON_VERSION_ENV not in env:
        try:
            from importlib.metadata import version

            env[_BRIDGE_PYTHON_VERSION_ENV] = version("cursor-sdk")
        except Exception:
            pass
    return env


@dataclass(frozen=True)
class BridgeEndpoint:
    url: str
    auth_token: str
    schema_version: int = 1
    server_version: str = ""
    pid: int | None = None
    workspace_ref: str = ""
    state_root: str = ""

    @classmethod
    def from_discovery(cls, discovery: Mapping[str, Any]) -> "BridgeEndpoint":
        if discovery.get("schemaVersion") != 1:
            raise CursorSDKError(
                f"Unsupported bridge discovery schema: {discovery.get('schemaVersion')}"
            )
        if (
            discovery.get("transport") != "tcp"
            or discovery.get("protocol") != "connect"
        ):
            raise CursorSDKError("Unsupported bridge transport discovery payload")
        url = str(discovery.get("url") or "")
        if not url:
            host = str(discovery.get("host") or "")
            port = discovery.get("port")
            if not host or not port:
                raise CursorSDKError("Bridge discovery payload is missing a URL")
            if ":" in host and not host.startswith("["):
                host = f"[{host}]"
            url = f"http://{host}:{port}"
        auth_token = str(discovery.get("authToken") or "")
        token_file = discovery.get("authTokenFile")
        if not auth_token and token_file:
            auth_token = Path(str(token_file)).read_text(encoding="utf-8")
        auth_token = auth_token.strip()
        if not auth_token:
            raise CursorSDKError("Bridge discovery payload is missing an auth token")
        return cls(
            url=url,
            auth_token=auth_token,
            schema_version=int(discovery["schemaVersion"]),
            server_version=str(discovery.get("serverVersion") or ""),
            pid=int(discovery["pid"]) if discovery.get("pid") is not None else None,
            workspace_ref=str(discovery.get("workspaceRef") or ""),
            state_root=str(discovery.get("stateRoot") or ""),
        )


class Bridge:
    """Managed cursor-sdk-bridge subprocess."""

    def __init__(
        self,
        endpoint: BridgeEndpoint,
        process: subprocess.Popen[str] | None = None,
        store_callback_server: StoreCallbackServer | None = None,
        tool_callback_server: ToolCallbackServer | None = None,
    ) -> None:
        self.endpoint = endpoint
        self.process = process
        self._store_callback_server = store_callback_server
        self._tool_callback_server = tool_callback_server

    @property
    def store_callback_enabled(self) -> bool:
        return self._store_callback_server is not None

    @property
    def tool_callback_enabled(self) -> bool:
        return self._tool_callback_server is not None

    def register_custom_tools(
        self, agent_id: str, tools: Mapping[str, CustomTool]
    ) -> None:
        if self._tool_callback_server is None:
            raise CursorSDKError("Bridge has no tool callback server")
        self._tool_callback_server.register_agent(agent_id, tools)

    def unregister_custom_tools(self, agent_id: str) -> None:
        if self._tool_callback_server is not None:
            self._tool_callback_server.unregister_agent(agent_id)

    @classmethod
    def launch(
        cls,
        command: str
        | os.PathLike[str]
        | Sequence[str | os.PathLike[str]]
        | None = None,
        *,
        workspace: str | os.PathLike[str] | None = None,
        state_root: str | os.PathLike[str] | None = None,
        host: str | None = None,
        port: int | None = None,
        timeout: float = 30,
        local: LocalAgentOptions | Mapping[str, Any] | None = None,
        store_handler: LocalAgentStoreHandler | None = None,
    ) -> "Bridge":
        if command is None:
            argv = [resolve_bridge_path()]
        elif isinstance(command, (str, os.PathLike)):
            argv = [os.fspath(command)]
        else:
            argv = [os.fspath(arg) for arg in command]
        if workspace:
            argv.extend(["--workspace", os.fspath(workspace)])
        if state_root:
            argv.extend(["--state-root", os.fspath(state_root)])
        if host:
            argv.extend(["--host", host])
        if port is not None:
            argv.extend(["--port", str(port)])

        store_callback_server: StoreCallbackServer | None = None
        env = dict(_bridge_subprocess_env())
        handler = resolve_store_callback_handler_for_launch(
            local=local,
            store_handler=store_handler,
        )
        if handler is not None:
            store_callback_server = StoreCallbackServer(handler)
            # Pass the callback URL + token via argv only, never the subprocess
            # env: the bridge's model-driven shell tools inherit its env, so a
            # token there could be read by a prompt-injected command.
            argv.extend(store_callback_bridge_argv(store_callback_server.endpoint))
        tool_callback_server = ToolCallbackServer()
        argv.extend(tool_callback_bridge_argv(tool_callback_server.endpoint))
        # Bind the store for every operation (create/list/get), like the TS SDK.
        argv.extend(local_store_bridge_argv(local))

        process = subprocess.Popen(
            argv,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.PIPE,
            text=True,
            env=env,
        )
        try:
            discovery = _read_discovery(process, timeout)
            return cls(
                BridgeEndpoint.from_discovery(discovery),
                process,
                store_callback_server,
                tool_callback_server,
            )
        except Exception:
            if store_callback_server is not None:
                store_callback_server.close()
            if tool_callback_server is not None:
                tool_callback_server.close()
            _terminate_process(process)
            raise

    def close(self) -> None:
        if self.process is None:
            return
        # Best-effort graceful shutdown via a direct Connect RPC; using the
        # full `Client` here would force a function-local import to break
        # the `_bridge -> _client -> _bridge` cycle. The helper handles
        # connection-pool cleanup (`with DefaultHttpxClient(...)`) and
        # swallows transport errors so we always proceed to terminate.
        post_bridge_shutdown(
            self.endpoint.url, self.endpoint.auth_token, grace_seconds=0
        )
        _terminate_process(self.process)
        self.process = None
        if self._store_callback_server is not None:
            self._store_callback_server.close()
            self._store_callback_server = None
        if self._tool_callback_server is not None:
            self._tool_callback_server.close()
            self._tool_callback_server = None

    def __enter__(self) -> "Bridge":
        return self

    def __exit__(self, exc_type: object, exc: object, tb: object) -> None:
        self.close()


def _read_discovery(
    process: subprocess.Popen[str], timeout: float
) -> Mapping[str, Any]:
    if process.stderr is None:
        raise CursorSDKError("Bridge process stderr is unavailable")
    stderr_fd = process.stderr.fileno()
    was_blocking = os.get_blocking(stderr_fd)
    os.set_blocking(stderr_fd, False)

    with selectors.DefaultSelector() as selector:
        try:
            selector.register(stderr_fd, selectors.EVENT_READ)
            decoder = codecs.getincrementaldecoder("utf-8")(errors="replace")
            deadline = time.monotonic() + timeout
            stderr_lines: list[str] = []
            pending = ""

            def drain_available() -> Mapping[str, Any] | None:
                nonlocal pending
                while True:
                    try:
                        chunk = os.read(stderr_fd, 8192)
                    except BlockingIOError:
                        return None
                    if not chunk:
                        final_text = decoder.decode(b"", final=True)
                        if final_text:
                            pending += final_text
                        if pending:
                            line = pending
                            pending = ""
                            stderr_lines.append(line)
                            return parse_discovery_line(line)
                        return None
                    pending += decoder.decode(chunk)
                    while "\n" in pending:
                        line, pending = pending.split("\n", 1)
                        line += "\n"
                        stderr_lines.append(line)
                        discovery = parse_discovery_line(line)
                        if discovery is not None:
                            return discovery

            while time.monotonic() < deadline:
                discovery = drain_available()
                if discovery is not None:
                    return discovery
                exit_code = process.poll()
                if exit_code is not None:
                    discovery = drain_available()
                    if discovery is not None:
                        return discovery
                    raise CursorSDKError(
                        f"Bridge exited before discovery with status {exit_code}: "
                        + "".join(stderr_lines)
                        + pending
                    )
                selector.select(timeout=min(0.1, max(0.0, deadline - time.monotonic())))
            raise CursorSDKError("Timed out waiting for bridge discovery")
        finally:
            os.set_blocking(stderr_fd, was_blocking)


def parse_discovery_line(line: str) -> Mapping[str, Any] | None:
    """Parse a `cursor-sdk-bridge ready ...` stderr line.

    Returns the discovery payload mapping, `None` if the line is not a
    discovery line, or raises `CursorSDKError` if the payload is malformed.
    Shared between the sync and async bridge launchers so they agree on the
    wire format.
    """
    if not line.startswith(READY_LINE_PREFIX):
        return None
    payload = line[len(READY_LINE_PREFIX) :]
    try:
        loaded = json.loads(payload)
    except json.JSONDecodeError as error:
        raise CursorSDKError("Bridge emitted invalid discovery JSON") from error
    if not isinstance(loaded, Mapping):
        raise CursorSDKError("Bridge discovery payload must be an object")
    return loaded


def _terminate_process(process: subprocess.Popen[str]) -> None:
    if process.poll() is not None:
        return
    process.terminate()
    try:
        process.wait(timeout=5)
    except subprocess.TimeoutExpired:
        process.kill()
        process.wait(timeout=5)
